// HasOutlet applies the HasEdge predicate on the "outlet" edge.
func HasOutlet() predicate.OutletSetting {
	return predicate.OutletSetting(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2O, true, OutletTable, OutletColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasOutletWith applies the HasEdge predicate on the "outlet" edge with a given conditions (other predicates).
func HasOutletWith(preds ...predicate.Outlet) predicate.OutletSetting {
	return predicate.OutletSetting(func(s *sql.Selector) {
		step := newOutletStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.OutletSetting) predicate.OutletSetting {
	return predicate.OutletSetting(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.OutletSetting) predicate.OutletSetting {
	return predicate.OutletSetting(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.OutletSetting) predicate.OutletSetting {
	return predicate.OutletSetting(sql.NotPredicates(p))
}
